using (Graphics g = Graphics.FromImage(bmp))
                {
                    IntPtr hdc = g.GetHdc();
                    try
                    {
                        // PrintWindow 标志位: 2 (PW_CLIENTONLY | PW_RENDERFULLCONTENT) 
                        // 能更好支持某些应用，但只支持 Win8.1+
                        // 如果失败，尝试 0
                        bool success = PrintWindow(handle, hdc, 2);
                        if (!success) success = PrintWindow(handle, hdc, 0);

                        if (!success)
                        {
                            g.ReleaseHdc(hdc);
                            return null; // 失败，回退
                        }
                    }
                    finally
                    {
                        g.ReleaseHdc(hdc);
                    }
                }

